1	use std::collections::HashMap;
2	use std::path::Path;
3	use std::sync::{Arc, Mutex};
4	use std::thread::ThreadId;
5	
6	use chrono::Utc;
7	use orbit_agent::loop_engine::InMemorySink;
8	use orbit_agent::loop_engine::audit::{AuditSink, LoopAuditEvent};
9	use orbit_common::types::activity_job::{
10	    AUDIT_ENVELOPE_SCHEMA_VERSION, V2AuditEnvelope, V2AuditEvent, V2AuditEventKind,
11	};
12	use thiserror::Error;
13	
14	use super::jsonl_sink::V2JsonlSink;
15	
16	/// Writes §7 v2 audit envelope events. Nests the existing loop-engine events
17	/// underneath an Activity event via `parent_event_id` so the whole tree
18	/// (Run → Step → Activity → http.*/tool.call.*) is traversable by ID.
19	///
20	/// This writer owns the run_id / agent_identity context and emits events both
21	/// as structured JSON (for orbit-audit consumers) and as an inner loop sink
22	/// passthrough (so loop-level http.* and tool.call.* events continue to flow
23	/// through the existing JSONL path).
24	pub struct V2AuditWriter {
25	    run_id: String,
26	    agent_identity: String,
27	    workspace_path: Option<String>,
28	    inner: Arc<dyn AuditSink>,
29	    envelope_sink: Option<Arc<V2JsonlSink>>,
30	    events: Mutex<Vec<V2AuditEvent>>,
31	    event_counter: Mutex<u64>,
32	    parent_stacks: Mutex<HashMap<ThreadId, Vec<String>>>,
33	}
34	
35	/// Restores the calling thread's previous parent stack on drop.
36	pub(crate) struct ParentStackGuard<'a> {
37	    writer: &'a V2AuditWriter,
38	    thread_id: ThreadId,
39	    previous: Option<Vec<String>>,
40	}
41	
42	#[derive(Debug, Error)]
43	pub enum WriteError {
44	    #[error("audit writer mutex poisoned")]
45	    Poisoned,
46	}
47	
48	impl V2AuditWriter {
49	    pub fn new(
50	        run_id: impl Into<String>,
51	        agent_identity: impl Into<String>,
52	        inner: Arc<dyn AuditSink>,
53	    ) -> Self {
54	        Self {
55	            run_id: run_id.into(),
56	            agent_identity: agent_identity.into(),
57	            workspace_path: None,
58	            inner,
59	            envelope_sink: None,
60	            events: Mutex::new(Vec::new()),
61	            event_counter: Mutex::new(0),
62	            parent_stacks: Mutex::new(HashMap::new()),
63	        }
64	    }
65	
66	    /// Attach a JSONL sink for §7 envelope events. When set, every emitted
67	    /// envelope event is persisted to disk alongside the in-memory snapshot
68	    /// (resolves Phase 2a design-risk #2).
69	    pub fn with_envelope_sink(mut self, sink: Arc<V2JsonlSink>) -> Self {
70	        self.envelope_sink = Some(sink);
71	        self
72	    }
73	
74	    /// Attach the originating workspace path for §7 `workspace_path`
75	    /// provenance. Call before the writer is shared (`Arc::new`). Absent
76	    /// when the caller has no meaningful workspace (stub hosts, smokes).
77	    pub fn with_workspace_path(mut self, path: impl Into<String>) -> Self {
78	        self.workspace_path = Some(path.into());
79	        self
80	    }
81	
82	    /// High-level constructor for CLI / library callers that don't want to
83	    /// name the loop-level sink types directly (orbit-core's primary use
84	    /// case). Creates an `InMemorySink` backed by `audit_root/blobs/` and a
85	    /// `V2JsonlSink` at `audit_root/v2_loop/{run_id}.jsonl`, wires them
86	    /// together, and returns a ready-to-dispatch writer.
87	    ///
88	    /// Callers that need a custom sink configuration use `new` +
89	    /// `with_envelope_sink` directly.
90	    pub fn with_disk_sinks(
91	        audit_root: &Path,
92	        run_id: impl Into<String>,
93	        agent_identity: impl Into<String>,
94	        workspace_path: Option<&Path>,
95	    ) -> std::io::Result<Arc<Self>> {
96	        let run_id = run_id.into();
97	        let blob_dir = audit_root.join("blobs");
98	        std::fs::create_dir_all(&blob_dir)?;
99	        let inner: Arc<dyn AuditSink> = Arc::new(InMemorySink::new(blob_dir));
100	        let envelope_sink = Arc::new(V2JsonlSink::open(audit_root, &run_id)?);
101	        let mut writer = Self::new(run_id, agent_identity, inner).with_envelope_sink(envelope_sink);
102	        if let Some(path) = workspace_path {
103	            writer = writer.with_workspace_path(path.display().to_string());
104	        }
105	        Ok(Arc::new(writer))
106	    }
107	
108	    /// Path to the JSONL sink's log file, if one is attached. Used by CLI
109	    /// callers to report where envelope events were persisted.
110	    pub fn envelope_log_path(&self) -> Option<std::path::PathBuf> {
111	        self.envelope_sink
112	            .as_ref()
113	            .map(|s| s.log_path().to_path_buf())
114	    }
115	
116	    /// Emit a v2 envelope event of the given kind. Returns the event_id so
117	    /// callers can use it as a parent for nested events.
118	    pub fn emit(&self, kind: V2AuditEventKind) -> Result<String, WriteError> {
119	        let event_id = self.next_event_id()?;
120	        let parent_event_id = self.current_parent_event_id()?;
121	        let event_type = event_type_of(&kind).to_string();
122	        let envelope = V2AuditEnvelope {
123	            schema_version: AUDIT_ENVELOPE_SCHEMA_VERSION,
124	            event_type,
125	            event_id: event_id.clone(),
126	            ts: Utc::now(),
127	            run_id: self.run_id.clone(),
128	            agent_identity: self.agent_identity.clone(),
129	            parent_event_id,
130	            workspace_path: self.workspace_path.clone(),
131	        };
132	        let event = V2AuditEvent { envelope, kind };
133	        if let Some(sink) = &self.envelope_sink {
134	            // Disk persistence failures should not crash the run. Emitting
135	            // the event to the in-memory snapshot is the load-bearing path;
136	            // JSONL is for review-time inspection.
137	            let _ = sink.write(&event);
138	        }
139	        self.events
140	            .lock()
141	            .map_err(|_| WriteError::Poisoned)?
142	            .push(event);
143	        Ok(event_id)
144	    }
145	
146	    /// Push a parent context so subsequent events nest beneath it.
147	    pub fn push_parent(&self, event_id: String) -> Result<(), WriteError> {
148	        let thread_id = std::thread::current().id();
149	        self.parent_stacks
150	            .lock()
151	            .map_err(|_| WriteError::Poisoned)?
152	            .entry(thread_id)
153	            .or_default()
154	            .push(event_id);
155	        Ok(())
156	    }
157	
158	    /// Pop the most recent parent context.
159	    pub fn pop_parent(&self) -> Result<Option<String>, WriteError> {
160	        let thread_id = std::thread::current().id();
161	        let mut stacks = self
162	            .parent_stacks
163	            .lock()
164	            .map_err(|_| WriteError::Poisoned)?;
165	        let popped = {
166	            let stack = stacks.entry(thread_id).or_default();
167	            stack.pop()
168	        };
169	        if stacks.get(&thread_id).is_some_and(Vec::is_empty) {
170	            stacks.remove(&thread_id);
171	        }
172	        Ok(popped)
173	    }
174	
175	    /// Snapshot the current thread's parent stack so callers can propagate
176	    /// parentage into spawned worker threads.
177	    pub(crate) fn parent_stack_snapshot(&self) -> Result<Vec<String>, WriteError> {
178	        let thread_id = std::thread::current().id();
179	        Ok(self
180	            .parent_stacks
181	            .lock()
182	            .map_err(|_| WriteError::Poisoned)?
183	            .get(&thread_id)
184	            .cloned()
185	            .unwrap_or_default())
186	    }
187	
188	    /// Install a parent stack for the current thread and restore the previous
189	    /// value when the returned guard is dropped.
190	    pub(crate) fn install_parent_stack(
191	        &self,
192	        stack: Vec<String>,
193	    ) -> Result<ParentStackGuard<'_>, WriteError> {
194	        let thread_id = std::thread::current().id();
195	        let previous = self
196	            .parent_stacks
197	            .lock()
198	            .map_err(|_| WriteError::Poisoned)?
199	            .insert(thread_id, stack);
200	        Ok(ParentStackGuard {
201	            writer: self,
202	            thread_id,
203	            previous,
204	        })
205	    }
206	
207	    /// Snapshot of emitted events (for smoke verification).
208	    pub fn events_snapshot(&self) -> Result<Vec<V2AuditEvent>, WriteError> {
